		if (EXTRACT_32BITS(&hellop->hello_bdr) != 0)

			ND_PRINT((ndo, ", Backup Designated Router %s",

			    ipaddr_string(ndo, &hellop->hello_bdr)));

		if (ndo->ndo_vflag > 1) {

			ND_PRINT((ndo, "\n\t  Neighbor List:"));

			ap = hellop->hello_neighbor;

			while ((const u_char *)ap < dataend) {

