/* stuctures definitions */

struct subscriber {

	LIST_ENTRY(subscriber) entries;

	struct upnp_event_notify * notify;

	time_t timeout;

	uint32_t seq;

	enum subscriber_service_enum service;

	char uuid[42];

	char callback[];

};



struct upnp_event_notify {

	LIST_ENTRY(upnp_event_notify) entries;

    int s;  /* socket */

    enum { ECreated=1,

	       EConnecting,

	       ESending,

	       EWaitingForResponse,

	       EFinished,

	       EError } state;

    struct subscriber * sub;

    char * buffer;

    int buffersize;

	int tosend;

    int sent;

	const char * path;

#ifdef ENABLE_IPV6

	int ipv6;

	char addrstr[48];

#else

	char addrstr[16];

#endif

	char portstr[8];

};



