		       "upnp_event_create_notify");

	}

#endif

	/* set socket non blocking */

	if(!set_non_blocking(obj->s)) {

		syslog(LOG_ERR, "%s: set_non_blocking(): %m",

		       "upnp_event_create_notify");

		goto error;

	}

	if(sub)

		sub->notify = obj;

	LIST_INSERT_HEAD(&notifylist, obj, entries);

	return;

error:

	if(obj->s >= 0)

		close(obj->s);

	free(obj);

