	read_lock(&mrt_lock);

	if (reg_vif_num >= 0)

		reg_dev = mrt->vif6_table[reg_vif_num].dev;

	if (reg_dev)

		dev_hold(reg_dev);

	read_unlock(&mrt_lock);



	if (!reg_dev)

		goto drop;



	skb->mac_header = skb->network_header;

	skb_pull(skb, (u8 *)encap - skb->data);

