	    nla_put_in6_addr(skb, RTA_DST, &c->mf6c_mcastgrp))

		goto nla_put_failure;

	err = __ip6mr_fill_mroute(mrt, skb, c, rtm);

	/* do not break the dump if cache is unresolved */

	if (err < 0 && err != -ENOENT)

		goto nla_put_failure;



