/* Read field indicating which parameters are present */

static void

rdp_in_present(STREAM s, uint32 * present, uint8 flags, int size)

{

	uint8 bits;

	int i;



	if (flags & RDP_ORDER_SMALL)

	{

		size--;

	}



	if (flags & RDP_ORDER_TINY)

	{

		if (size < 2)

			size = 0;

		else

			size -= 2;

	}



	*present = 0;

	for (i = 0; i < size; i++)

	{

		in_uint8(s, bits);

		*present |= bits << (i * 8);

	}

