static int

parse_delta(uint8 * buffer, int *offset)

{

	int value = buffer[(*offset)++];

	int two_byte = value & 0x80;



	if (value & 0x40)	/* sign bit */

		value |= ~0x3f;

	else

		value &= 0x3f;



	if (two_byte)

		value = (value << 8) | buffer[(*offset)++];



	return value;

},c,safe,,,

static void

rdp_in_colour(STREAM s, uint32 * colour)

{

	uint32 i;

	in_uint8(s, i);

	*colour = i;

	in_uint8(s, i);

	*colour |= i << 8;

	in_uint8(s, i);

	*colour |= i << 16;

