rdp_parse_bounds(STREAM s, BOUNDS * bounds)

{

	uint8 present;



	in_uint8(s, present);



	if (present & 1)

		rdp_in_coord(s, &bounds->left, False);

	else if (present & 16)

		rdp_in_coord(s, &bounds->left, True);



	if (present & 2)

