static void

process_compressed_8x8_brush_data(uint8 * in, uint8 * out, int Bpp)

{

	int x, y, pal_index, in_index, shift, do2, i;

	uint8 *pal;



	in_index = 0;

	pal = in + 16;

	/* read it bottom up */

	for (y = 7; y >= 0; y--)

	{

		/* 2 bytes per row */

		x = 0;

		for (do2 = 0; do2 < 2; do2++)

		{

			/* 4 pixels per byte */

			shift = 6;

			while (shift >= 0)

			{

