	    errmsgbuf, errbuf) == -1)

	{

		// That failed; log a message and give up.

		rpcapd_log(LOGPRIO_ERROR, "Send to client failed: %s", errbuf);

		return -1;

	}



	// Check if all the data has been read; if not, discard the data in excess

	if (rpcapd_discard(pars->sockctrl, plen) == -1)

	{

		return -1;

	}

	return 0;

