	return 0;



error:

	if (rpcapd_discard(pars->sockctrl, plen) == -1)

	{

		return -1;

	}

	rpcap_senderror(pars->sockctrl, ver, PCAP_ERR_UPDATEFILTER,

	    errmsgbuf, NULL);



