	netadrtype_t family = NA_UNSPEC;



	if ( argc != 2 && argc != 3 ) {

		Com_Printf( "usage: connect [-4|-6] server\n");

		return;

	}



	if(argc == 2)

		server = Cmd_Argv(1);

	else

	{

		if(!strcmp(Cmd_Argv(1), "-4"))

			family = NA_IP;

		else if(!strcmp(Cmd_Argv(1), "-6"))

			family = NA_IP6;

		else

			Com_Printf( "warning: only -4 or -6 as address type understood.\n");



		server = Cmd_Argv(2);

	}



