            'image'       => $data['image'],

            'alias'       => $data['alias'],

            'category_id' => $data['category_id'],

            'sort'        => $data['sort'],

            'status'      => empty($data['status']) ? 0 : 1,

            'store_id'    => session('adminStoreId'),

