static int afiucv_pm_freeze(struct device *dev)

{

	struct iucv_sock *iucv;

	struct sock *sk;

	int err = 0;



#ifdef CONFIG_PM_DEBUG

	printk(KERN_WARNING "afiucv_pm_freeze\n");

#endif

