	high_nmcpy(user_data, sa->siucv_name);

	low_nmcpy(user_data, iucv->src_name);

	ASCEBC(user_data, sizeof(user_data));



	/* Create path. */

	iucv->path = iucv_path_alloc(iucv->msglimit,

				     IUCV_IPRMDATA, GFP_KERNEL);

