	if (err) {

		iucv_sever_path(nsk, 1);

		iucv_sock_kill(nsk);

		goto fail;

	}



	iucv_accept_enqueue(sk, nsk);



	/* Wake up accept */

	nsk->sk_state = IUCV_CONNECTED;

	sk->sk_data_ready(sk, 1);

	err = 0;

fail:

	bh_unlock_sock(sk);

	return 0;

