	memcpy(tmpName, trans_hdr->srcAppName, 8);

	memcpy(trans_hdr->srcUserID, trans_hdr->destUserID, 8);

	memcpy(trans_hdr->srcAppName, trans_hdr->destAppName, 8);

	memcpy(trans_hdr->destUserID, tmpID, 8);

