static void

S_pat_upgrade_to_utf8(pTHX_ RExC_state_t * const pRExC_state,

		    char **pat_p, STRLEN *plen_p, int num_code_blocks)

{

    U8 *const src = (U8*)*pat_p;

    U8 *dst, *d;

    int n=0;

    STRLEN s = 0;

    bool do_end = 0;

    GET_RE_DEBUG_FLAGS_DECL;



