    PERL_ARGS_ASSERT_SKIP_TO_BE_IGNORED_TEXT;



    assert( ! UTF || UTF8_IS_INVARIANT(**p) || UTF8_IS_START(**p));



    for (;;) {

	if (RExC_end - (*p) >= 3

	    && *(*p)     == '('

	    && *(*p + 1) == '?'

	    && *(*p + 2) == '#')

	{

	    while (*(*p) != ')') {

		if ((*p) == RExC_end)

		    FAIL("Sequence (?#... not terminated");

		(*p)++;

	    }

	    (*p)++;

	    continue;

	},c,vulnerable,,,

