 */

regnode *

Perl_regnext(pTHX_ regnode *p)

{

    I32 offset;



    if (!p)

	return(NULL);



    if (OP(p) > REGNODE_MAX) {		/* regnode.type is unsigned */

	Perl_croak(aTHX_ "Corrupted regexp opcode %d > %d",

                                                (int)OP(p), (int)REGNODE_MAX);

    }



    offset = (reg_off_by_arg[OP(p)] ? ARG(p) : NEXT_OFF(p));

    if (offset == 0)

	return(NULL);



    return(p+offset);

},c,vulnerable,,,

