   * @param name

   *          entry name.

   * @return contents of the entry or <code>null</code> if it was not found.

   */

  public static byte[] unpackEntry(File zip, String name) {

    ZipFile zf = null;

    try {

      zf = new ZipFile(zip);

      return doUnpackEntry(zf, name);

    }

    catch (IOException e) {

      throw ZipExceptionUtil.rethrow(e);

    }

    finally {

      closeQuietly(zf);

    }

  }



