  public static byte[] unpackEntry(File zip, String name, Charset charset) {

    ZipFile zf = null;

    try {

      if (charset != null) {

        zf = new ZipFile(zip, charset);

      }

      else {

        zf = new ZipFile(zip);

      }

      return doUnpackEntry(zf, name);

