  private static class ByteArrayUnpacker implements ZipEntryCallback {



    private byte[] bytes;



    public void process(InputStream in, ZipEntry zipEntry) throws IOException {

      bytes = IOUtils.toByteArray(in);

    }



    public byte[] getBytes() {

      return bytes;

    }



  }



